export default function LoginPage({ isDark, setIsDark }) {
  const navigate  = useNavigate();
  const canvasRef = useRef(null);

  const [form, setForm]         = useState({ email: '', password: '' });
  const [errors, setErrors]     = useState({});
  const [apiError, setApiError] = useState('');
  const [loading, setLoading]   = useState(false);
  const [coords, setCoords]     = useState('14°35\'N · 120°58\'E');

  useParticles(canvasRef, isDark);

  // Animate coordinates
  useEffect(() => {
    const interval = setInterval(() => {
      const lat = (14 + Math.random() * 0.01).toFixed(4);
      const lng = (120 + Math.random() * 0.01).toFixed(4);
      setCoords(`${lat}°N · ${lng}°E`);
    }, 2000);
    return () => clearInterval(interval);
  }, []);

  function validate() {
    const errs = {};
    if (!form.email.trim()) {
      errs.email = 'EMAIL_REQUIRED';
    } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(form.email)) {
      errs.email = 'INVALID_EMAIL_FORMAT';
    }
    if (!form.password) {
      errs.password = 'PASSWORD_REQUIRED';
    } else if (form.password.length < 6) {
      errs.password = 'MIN_LENGTH: 6 CHARS';
    }
    return errs;
  }

  function handleChange(e) {
    const { name, value } = e.target;
    setForm(prev => ({ ...prev, [name]: value }));
    if (errors[name]) setErrors(prev => ({ ...prev, [name]: '' }));
    setApiError('');
  }

  async function handleSubmit(e) {
    e.preventDefault();
    const errs = validate();
    if (Object.keys(errs).length > 0) { setErrors(errs); return; }
    setLoading(true);
    setApiError('');
    try {
      const res  = await fetch(API_URL, {
        method:  'POST',
        headers: { 'Content-Type': 'application/json' },
        body:    JSON.stringify(form),
      });
      const data = await res.json();
      if (data.success) {
        localStorage.setItem('token', data.token);
        localStorage.setItem('user', JSON.stringify(data.user));
        navigate('/');
      } else {
        setApiError(data.message?.toUpperCase() || 'AUTH_FAILED');
      }
    } catch {
      setApiError('CONNECTION_REFUSED — CHECK SERVER STATUS');
    } finally {
      setLoading(false);
    }
  }

  return (
    <div className={`login-page ${isDark ? 'dark' : 'light'}`}>

      {/* ── LEFT PANEL ── */}
      <div className="login-left">
        <canvas ref={canvasRef} id="particle-canvas"
          style={{ position:'absolute', inset:0, width:'100%', height:'100%' }} />

        <div className="left-orb" />
        <div className="login-divider-line" />

        {/* Globe decoration */}
        <div className="globe-deco">
          <div className="globe-line-v" />
        </div>

        {/* Branding */}
        <div className="login-brand">
          <div className="login-brand-title">IP Geolocation</div>
          <div className="login-brand-sub">IP Geolocation Platform</div>
        </div>

        {/* Center coords */}
        <div className="login-coords" style={{
          position:'absolute', top:'50%', right:'60px',
          transform:'translateY(-50%)', zIndex:2
        }}>
          <div className="login-coords-val">{coords}</div>
        </div>

        {/* Stats */}
        <div className="login-stats">
          <div className="login-stat">
            UPTIME <span className="login-stat-val">99.98%</span>
          </div>
          <div className="login-stat">
            NODES <span className="login-stat-val">142</span>
          </div>
          <div className="login-stat">
            SIGNAL <span className="login-stat-val active">ACTIVE</span>
          </div>
        </div>
      </div>

      {/* ── RIGHT PANEL ── */}
      <div className="login-right">

        {/* Theme toggle */}
        <button className="theme-toggle" onClick={() => setIsDark(d => !d)}>
          {isDark ? Icons.sun : Icons.moon}
          <span>{isDark ? 'LIGHT' : 'DARK'}</span>
        </button>

        {/* Header */}
        <div className="login-right-coords">{coords}</div>
        <div className="login-right-title">Access Terminal</div>
        <div className="login-right-sub">Sign in to your dashboard</div>
        <div className="login-right-divider" />

        {/* Error */}
        {apiError && (
          <div className="alert-error">
            {Icons.alert} {apiError}
          </div>
        )}

        {/* Form */}
        <form onSubmit={handleSubmit} noValidate>
          <div className="form-group">
            <label>Email</label>
            <input
              name="email" type="email"
              placeholder="user@domain.com"
              value={form.email}
              onChange={handleChange}
              className={errors.email ? 'has-error' : ''}
              autoComplete="email"
              autoCapitalize="none"
              autoCorrect="off"
              spellCheck="false"
            />
            {errors.email && (
              <span className="error-msg">{Icons.alert} {errors.email}</span>
            )}
          </div>

          <div className="form-group">
            <label>Password</label>
            <input
              name="password" type="password"
              placeholder="••••••••"
              value={form.password}
              onChange={handleChange}
              className={errors.password ? 'has-error' : ''}
              autoComplete="current-password"
            />
            {errors.password && (
              <span className="error-msg">{Icons.alert} {errors.password}</span>
            )}
          </div>

          <button type="submit" className="login-btn" disabled={loading}>
            <span>{loading ? 'AUTHENTICATING...' : 'AUTHENTICATE'}</span>
            <span className="login-btn-arrow">
              {loading ? Icons.spinner : '→'}
            </span>
          </button>
        </form>

        {/* Footer */}
        <div className="login-footer">
          <span className="login-footer-text">SIGNAL ENCRYPTED · TLS 1.3</span>
          <div className="login-hint">
            <strong>admin@example.com</strong><br/>
            <strong>password123</strong>
          </div>
        </div>
      </div>
    </div>
  );
}
